import React, { useState, useEffect, useRef } from 'react';
import { 
  IonPage, IonHeader, IonToolbar, IonTitle, IonContent, IonFooter,
  IonButtons, IonButton, IonIcon, IonTextarea, IonAvatar, IonBackButton
} from '@ionic/react';
import { useParams } from 'react-router-dom';
import { cameraOutline, sendOutline, micOutline } from 'ionicons/icons';
import { Capacitor } from '@capacitor/core';
import { Camera, CameraResultType, CameraSource } from '@capacitor/camera';
import { Filesystem, Directory } from '@capacitor/filesystem';
import { AudioRecorder } from '@capgo/capacitor-audio-recorder';
import { useChatStorage } from '../hooks/useChatStorage';
import { Message } from '../types';
import './ChatRoom.css';

const ChatRoom: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const chatId = id || '1';

  const [messages, setMessages] = useState<Message[]>([]);
  const [text, setText] = useState('');
  const [isRecording, setIsRecording] = useState(false);

  const contentRef = useRef<HTMLIonContentElement>(null);
  const { isReady, saveMessages, getMessages } = useChatStorage();

  useEffect(() => {
    if (isReady) {
      loadMessages();
    }
  }, [isReady, chatId]);

  const loadMessages = async () => {
    const saved = await getMessages(chatId);
    setMessages(saved);
    scrollToBottom();
  };

  const scrollToBottom = () => {
    setTimeout(() => {
      contentRef.current?.scrollToBottom(300);
    }, 100);
  };

  const handleSendText = async () => {
    if (!text.trim()) return;
    const newMsg: Message = {
      id: Date.now().toString(),
      text: text.trim(),
      timestamp: Date.now(),
      isSentByMe: true
    };

    const updated = [...messages, newMsg];
    setMessages(updated);
    setText('');
    await saveMessages(chatId, updated);
    scrollToBottom();
  };

  const handleCamera = async () => {
    try {
      const image = await Camera.getPhoto({
        quality: 90,
        allowEditing: false,
        resultType: CameraResultType.Uri,
        source: CameraSource.Camera
      });

      const finalUri = image.path || image.webPath || '';

      if (finalUri) {
        const newMsg: Message = {
          id: Date.now().toString(),
          imageUri: finalUri,
          timestamp: Date.now(),
          isSentByMe: true
        };

        const updated = [...messages, newMsg];
        setMessages(updated);
        await saveMessages(chatId, updated);
        scrollToBottom();
      }
    } catch (e) {
      console.error("Camera error:", e);
    }
  };

  const startRecording = async () => {
    try {
      const hasPermission = await AudioRecorder.requestAudioRecordingPermission();
      if (hasPermission) {
        await AudioRecorder.startRecording();
        setIsRecording(true);
      }
    } catch (e) {
      console.error("Audio recording start error:", e);
    }
  };

  const stopRecording = async () => {
    try {
      setIsRecording(false);
      const result = await AudioRecorder.stopRecording();

      const anyRes = result as any;
      let fileUriToSave = '';

      if (anyRes.uri) {
        // Platform returned a file URI (Native)
        const base64Data = await Filesystem.readFile({ path: anyRes.uri });
        const fileName = `audio_${Date.now()}.m4a`;
        const writeResult = await Filesystem.writeFile({
          path: fileName,
          data: base64Data.data,
          directory: Directory.Data
        });
        fileUriToSave = writeResult.uri;
      } else if (anyRes.blob) {
        // Platform returned a blob (Web)
        const base64Str = await new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onloadend = () => {
            resolve(reader.result as string);
          };
          reader.readAsDataURL(anyRes.blob);
        });
        const fileName = `audio_${Date.now()}.m4a`;
        const writeResult = await Filesystem.writeFile({
          path: fileName,
          data: base64Str,
          directory: Directory.Data
        });
        fileUriToSave = writeResult.uri;
      } else if (anyRes.recordDataBase64) {
        const fileName = `audio_${Date.now()}.m4a`;
        const writeResult = await Filesystem.writeFile({
          path: fileName,
          data: anyRes.recordDataBase64,
          directory: Directory.Data
        });
        fileUriToSave = writeResult.uri;
      }

      if (fileUriToSave) {
        const newMsg: Message = {
          id: Date.now().toString(),
          audioUri: fileUriToSave,
          timestamp: Date.now(),
          isSentByMe: true
        };
        const updated = [...messages, newMsg];
        setMessages(updated);
        await saveMessages(chatId, updated);
        scrollToBottom();
      }

    } catch (e) {
      console.error("Audio recording stop error:", e);
    }
  };

  const toggleRecording = () => {
    if (isRecording) {
      stopRecording();
    } else {
      startRecording();
    }
  };

  const getMediaUrl = (path: string) => {
    return Capacitor.convertFileSrc(path);
  };

  const formatTime = (ts: number) => {
    return new Date(ts).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  return (
    <IonPage className="chat-room">
      <IonHeader>
        <IonToolbar color="primary">
          <IonButtons slot="start">
            <IonBackButton defaultHref="/" />
            <IonAvatar style={{ width: 36, height: 36, margin: '0 8px' }}>
              <img src="https://ionicframework.com/docs/img/demos/avatar.svg" alt="Avatar" />
            </IonAvatar>
          </IonButtons>
          <IonTitle>Chat Contact</IonTitle>
        </IonToolbar>
      </IonHeader>

      <IonContent ref={contentRef}>
        <div className="messages-container">
          {messages.map((msg) => (
            <div key={msg.id} className={`message-bubble ${msg.isSentByMe ? 'sent' : 'received'}`}>
              {msg.imageUri && (
                <img 
                  src={getMediaUrl(msg.imageUri)} 
                  alt="sent image" 
                  className="message-image" 
                />
              )}
              {msg.audioUri && (
                <audio 
                  controls 
                  src={getMediaUrl(msg.audioUri)} 
                  className="message-audio" 
                />
              )}
              {msg.text && <p className="message-text">{msg.text}</p>}
              <span className="message-time">{formatTime(msg.timestamp)}</span>
            </div>
          ))}
        </div>
      </IonContent>

      <IonFooter>
        <IonToolbar>
          <div className="chat-footer">
            <IonButton fill="clear" color="medium" onClick={handleCamera}>
              <IonIcon slot="icon-only" icon={cameraOutline} />
            </IonButton>

            <IonTextarea
              className="chat-input"
              value={text}
              onIonInput={(e) => setText(e.detail.value!)}
              placeholder="Message"
              autoGrow
              rows={1}
            />

            {text.trim().length > 0 ? (
              <IonButton fill="clear" color="primary" onClick={handleSendText}>
                <IonIcon slot="icon-only" icon={sendOutline} />
              </IonButton>
            ) : (
              <IonButton fill="clear" color={isRecording ? 'danger' : 'primary'} onClick={toggleRecording}>
                <IonIcon slot="icon-only" icon={micOutline} />
              </IonButton>
            )}
          </div>
        </IonToolbar>
      </IonFooter>
    </IonPage>
  );
};

export default ChatRoom;
